import re

PII_PATTERNS = {
    "email": r'[\w.+-]+@[\w-]+\.[a-zA-Z]{2,}',
    "phone": r'\b(\+?1[-.\s]?)?\(?\d{3}\)?[-.\s]?\d{3}[-.\s]?\d{4}\b',
    "ssn": r'\b\d{3}-\d{2}-\d{4}\b',
    "credit_card": r'\b(?:\d[ -]?){13,16}\b',
}

def detect_pii(text: str) -> dict:
    """Returns detected PII types (not values) for logging/blocking decisions."""
    found = {}
    for pii_type, pattern in PII_PATTERNS.items():
        matches = re.findall(pattern, text)
        if matches:
            found[pii_type] = len(matches)
    return found

def pii_safe_call(prompt: str, block_on_pii: bool = True) -> str:
    """Refuse or warn when PII is detected in prompts going to external API."""
    pii = detect_pii(prompt)
    if pii and block_on_pii:
        raise ValueError(f"PII detected in prompt before external API call: {pii}. "
                         "Remove PII or use on-premises model.")
    elif pii:
        print(f"WARNING: PII detected ({pii}) — review before production use")
    # Proceed with sanitized call
    return f"[safe call with {len(prompt)} chars]"  # Replace with actual call
